// pageStr stringifies a page number for the templ URL builder.
func pageStr(n int) string {
	return strconv.Itoa(n)
}

// runStatusKey normalises an empty status to "queued" so the CSS
// selector class stays valid.
func runStatusKey(s string) string {
	if s == "" {
		return "queued"
	}
	return s
}

// formatRunTime renders a started-at timestamp like
// "2026-05-15 14:23:47" — local time, second precision (per user
// request). UTC fields are rendered in local TZ so operators can
// match against their wall clock.
func formatRunTime(t time.Time) string {
	if t.IsZero() {
		return "—"
	}
	return t.Local().Format("2006-01-02 15:04:05")
}

// formatRunDuration shows wall-clock duration when both start and
// end are known. Empty otherwise — caller's CSS hides the slot via
// :empty so the row layout stays tight.
func formatRunDuration(r mcp.RunSummary) string {
	if r.EndedAt == nil || r.StartedAt.IsZero() {
		return ""
	}
	d := r.EndedAt.Sub(r.StartedAt)
	if d < time.Second {
		return d.Truncate(time.Millisecond).String()
	}
	return d.Truncate(time.Second).String()
}

